const input = $input.first().json['Input Apple Podcast links'];
const urls = input.split('\n').filter(u => u.trim() !== '');
return urls.map(url => {
  const match = url.match(/id(\d+)/);
  return {
    json: {
      apple_url: url.trim(),
      podcastId: match ? match[1] : ''
    }
  };
});

const rawData = $input.item.json;
let data;
if (rawData.data !== undefined) {
    data = typeof rawData.data === 'string' ? JSON.parse(rawData.data) : rawData.data;
} else {
    data = rawData;
}
let rssUrl = '';
if (data.results && data.results.length > 0) { rssUrl = data.results[0].feedUrl; }
return { json: { rssUrl: rssUrl } };

const xml = $input.item.json.data;
const xmlString = typeof xml === 'string' ? xml : JSON.stringify(xml);
const originalUrl = $('Parse Input URLs').item.json.apple_url;
const urlParts = originalUrl.split('/');
const urlSlug = urlParts.find(part => part.includes('-') && part.length > 10) || '';
const searchTerms = urlSlug.toLowerCase().replace(/-/g, ' ');
const items = xmlString.split('<item>');
let mp3Url = '';
let episodeTitle = '';
let bestMatch = null;
let bestScore = 0;
for (let item of items) {
  const titleMatch = item.match(/<title><!\[CDATA\[([^\]]+)\]\]><\/title>/) || item.match(/<title>([^<]+)<\/title>/);
  if (titleMatch) {
    const itemTitle = titleMatch[1].toLowerCase();
    const words = searchTerms.split(' ').filter(w => w.length > 2);
    let score = 0;
    for (let word of words) { if (itemTitle.includes(word)) score++; }
    if (score > bestScore) { bestScore = score; bestMatch = item; episodeTitle = titleMatch[1]; }
  }
}
if (bestMatch) {
  const urlMatch = bestMatch.match(/<enclosure[^>]*url="([^"]+)"[^>]*type="audio/);
  if (urlMatch) { mp3Url = urlMatch[1]; }
}
if (!mp3Url) {
  const firstMatch = xmlString.match(/<enclosure[^>]*url="([^"]+)"[^>]*type="audio/);
  mp3Url = firstMatch ? firstMatch[1] : '';
  episodeTitle = 'First episode (no match found)';
}
return { json: { mp3Url: mp3Url, episodeTitle: episodeTitle, matchScore: bestScore, success: mp3Url ? true : false } };

const items = $input.all();

function mdToHtml(md) {
  const lines = md.split('\n');
  const out = [];
  let inList = false;
  for (const line of lines) {
    if (line.startsWith('- ')) {
      if (!inList) { out.push('<ul style="margin:8px 0;padding-left:20px">'); inList = true; }
      const content = line.slice(2)
        .replace(/\*\*(.+?)\*\*/g, '<strong>$1</strong>')
        .replace(/\[([^\]]+)\]\(([^)]+)\)/g, '<a href="$2" style="color:#0066cc">$1</a>');
      out.push(`<li style="margin:4px 0">${content}</li>`);
    } else {
      if (inList) { out.push('</ul>'); inList = false; }
      if (line.trim() === '') continue;
      const content = line
        .replace(/\*\*(.+?)\*\*/g, '<strong>$1</strong>')
        .replace(/\[([^\]]+)\]\(([^)]+)\)/g, '<a href="$2" style="color:#0066cc">$1</a>');
      out.push(`<p style="margin:6px 0">${content}</p>`);
    }
  }
  if (inList) out.push('</ul>');
  return out.join('\n');
}

let html = `<!DOCTYPE html>
<html><head><meta charset="UTF-8"></head>
<body style="font-family:Arial,sans-serif;line-height:1.6;color:#333;max-width:700px;margin:0 auto;padding:20px">
<h2 style="color:#1a1a1a;border-bottom:2px solid #eee;padding-bottom:10px">Podcast Summaries</h2>
<p style="color:#888;font-size:13px">Generated: ${new Date().toLocaleDateString()} &middot; ${items.length} episode(s)</p>
`;

for (let i = 0; i < items.length; i++) {
  const item = items[i].json;
  let summary = '';
  if (item.message && item.message.content) { summary = item.message.content; }
  else if (item.choices && item.choices[0] && item.choices[0].message) { summary = item.choices[0].message.content; }
  else if (item.content) { summary = item.content; }
  else { summary = 'Error: Could not extract summary'; }
  html += `<div style="border:1px solid #e0e0e0;border-radius:8px;padding:20px;margin:20px 0">${mdToHtml(summary)}</div>`;
}

html += `</body></html>`;

return { json: { html: html } };
